import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import "./stepper.css"

const stepperVariants = cva(
  "inline-flex items-center",
  {
    variants: {
      variant: {
        neutral: "stepper-neutral",
        brand: "stepper-brand",
      },
      size: {
        sm: "stepper-sm gap-[var(--layout-gap-xs)]",
        md: "stepper-md gap-[var(--layout-gap-sm)]",
      },
    },
    defaultVariants: {
      variant: "neutral",
      size: "md",
    },
  }
)

function Stepper({
  className,
  variant,
  size,
  current = 0,
  total,
  onStepClick,
  ...props
}: Omit<React.ComponentProps<"div">, "children"> &
  VariantProps<typeof stepperVariants> & {
    current?: number
    total: number
    onStepClick?: (step: number) => void
  }) {
  const safeTotal = Number.isFinite(total) ? Math.max(1, Math.floor(total)) : 1
  const safeCurrent = Math.max(0, Math.min(current, safeTotal - 1))

  return (
    <div
      data-slot="stepper"
      role="group"
      aria-label={`Step ${safeCurrent + 1} of ${safeTotal}`}
      className={cn(stepperVariants({ variant, size, className }))}
      {...props}
    >
      {Array.from({ length: safeTotal }, (_, i) => {
        const state =
          i < safeCurrent
            ? "complete"
            : i === safeCurrent
              ? "active"
              : "incomplete"

        const stateClass =
          state === "complete"
            ? "step-dot-complete"
            : state === "active"
              ? "step-dot-active"
              : "step-dot-incomplete"

        const shared = cn("step-dot rounded-full shrink-0", stateClass)

        if (onStepClick) {
          return (
            <button
              key={i}
              data-slot="step-dot"
              type="button"
              className={cn(shared, "step-dot-clickable")}
              aria-label={`Step ${i + 1}${state === "complete" ? " (completed)" : state === "active" ? " (current)" : ""}`}
              aria-current={state === "active" ? "step" : undefined}
              onClick={() => onStepClick(i)}
            />
          )
        }

        return (
          <span
            key={i}
            data-slot="step-dot"
            className={shared}
            aria-current={state === "active" ? "step" : undefined}
          />
        )
      })}
    </div>
  )
}

export { Stepper, stepperVariants }

/* ================================================================
 * STEPPER — Dot-based Step Indicator
 * Structure (flex, gap) lives in stepper.tsx via cva.
 * Theming (colors, sizes, transitions) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Size — custom properties per size
 * -------------------------------- */
.stepper-sm {
  --stepper-dot: var(--root-positive-4);
  --stepper-pill: var(--root-positive-10);
}

.stepper-md {
  --stepper-dot: var(--root-positive-5);
  --stepper-pill: var(--root-positive-11);
}

/* --------------------------------
 * Dot — base dimensions + transition
 * -------------------------------- */
.step-dot {
  height: var(--stepper-dot);
  width: var(--stepper-dot);
  transition: width 300ms ease, background-color 300ms ease;
}

/* --------------------------------
 * Dot — active pill override
 * -------------------------------- */
.step-dot-active {
  width: var(--stepper-pill);
}

/* --------------------------------
 * Reduced motion — slow, don't remove
 * -------------------------------- */
@media (prefers-reduced-motion: reduce) {
  .step-dot {
    transition-duration: 800ms;
  }
}

/* --------------------------------
 * Variant — scoped color variables
 * -------------------------------- */
.stepper-neutral {
  --stepper-complete: var(--text-base-moderate);
  --stepper-active: var(--text-base-strong);
  --stepper-incomplete: var(--background-neutral-medium-default);
}

.stepper-brand {
  --stepper-complete: var(--background-brand-strong-default);
  --stepper-active: var(--background-brand-strong-default);
  --stepper-incomplete: var(--background-neutral-medium-default);
}

/* --------------------------------
 * State colors
 * -------------------------------- */
.step-dot-complete {
  background-color: var(--stepper-complete);
}

.step-dot-active {
  background-color: var(--stepper-active);
}

.step-dot-incomplete {
  background-color: var(--stepper-incomplete);
}

/* --------------------------------
 * Clickable — hover, active, focus
 * -------------------------------- */
.step-dot-clickable {
  cursor: pointer;
  border: none;
  padding: 0;
  background: transparent;
}

.step-dot-clickable:hover {
  opacity: var(--root-opacity-7);
}

.step-dot-clickable:active {
  opacity: var(--root-opacity-6);
}

.step-dot-clickable:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--background-base), 0 0 0 4px var(--border-selected);
}
